import { useEffect, useState } from "react";

export default function useGetSingleAPOD() {
  // const [image, setImage] = useState(null);

  let key = 'hK9L5EdqbSfX3VLvK84iefSH0yV3te6DYTv1JLG4';
  const url = `https://api.nasa.gov/planetary/apod?api_key=${key}`;

  useEffect(() => {    
    
    const getPhoto = async () => {
      const response = await fetch(url, {
        method: 'GET'
      })
      .then(response => response.json())
      .then(data => {
        setImage(data);
        localStorage.setItem('currentDay', JSON.stringify(data));
      });
    };

    if (localStorage.getItem('currentDay') === null) {
      getPhoto();
    } else {
      return;
    }

    
  }, []);

  if (localStorage.getItem('currentDay')) {
    let image = localStorage.getItem('currentDay');
    const newImage = JSON.parse(image);
    return newImage;
  } else {
    return null;
  }
}
